    if (/\d/.test(pw)) s++;
    if (/[!@#$%^&*]/.test(pw)) s++;
    const labels = ["", "Weak", "Fair", "Good", "Strong"];
    const colors = ["", "#EF4444", "#F59E0B", "#3B82F6", "var(--primary)"];
    return { level: s, label: labels[s] || "", color: colors[s] || "var(--muted-foreground)" };
  };

