          <ToggleRow label="Allow colleagues to see my work schedule" desc="Team members can see your shift timings" on={toggles.showSchedule} onChange={() => toggle("showSchedule")} />
        </div>
      </div>

      <div className="bg-amber-500/5 border border-amber-500/20 rounded-2xl p-8 mb-6">
