          <ToggleRow label="Show my online status (green dot)" desc="Colleagues see when you're active in the system" on={toggles.showOnline} onChange={() => toggle("showOnline")} />
          <ToggleRow label="Allow HR to see my login activity" desc="HR can view login times for attendance purposes" on={toggles.loginActivity} onChange={() => {}} disabled />
          <p className="text-[12px] font-bold text-amber-500 flex items-center gap-1"><AlertTriangle size={12} /> Required by company policy</p>
          <ToggleRow label="Allow performance data to be used in team reports" desc="Your anonymized performance contributes to team analytics" on={toggles.allowPerformanceData} onChange={() => toggle("allowPerformanceData")} />
