const formatCurrency = (val: number) => {
  if (val >= 10000000) return `Γé╣${(val / 10000000).toFixed(1)}Cr`;
  if (val >= 100000) return `Γé╣${(val / 100000).toFixed(1)}L`;
  if (val >= 1000) return `Γé╣${(val / 1000).toFixed(1)}K`;
  return `Γé╣${val}`;
};

