                    {s.name}
                  </td>
                  <td
                    style={{
                      padding: "12px 16px",
                      fontSize: "13px",
                      fontWeight: 600,
                      color: "var(--muted-foreground)",
                    }}
                  >
                    <span
                      className="px-2 py-1 rounded-lg text-xs font-bold"
                      style={{
                        backgroundColor: "var(--muted)",
                        color: "var(--foreground)",
                        border: "1px solid var(--border)",
                      }}
                    >
                      {s.code}
                    </span>
                  </td>
                  <td
                    style={{
                      padding: "12px 16px",
                      fontSize: "13px",
                      color: "var(--foreground)",
                    }}
                  >
                    {s.type}
                  </td>
                  <td
                    style={{
                      padding: "12px 16px",
                      fontSize: "13px",
                      color: "var(--foreground)",
                    }}
