                          backgroundColor: "transparent",
                          border: "1px solid #00B87C",
                          borderRadius: "8px",
                          padding: "4px 10px",
                          fontSize: "12px",
                          fontWeight: 600,
                          color: "#00B87C",
                          cursor: "pointer",
