                {rolesList.map((role) => (
                  <th
                    key={role.id}
                    className="pb-3 text-center"
                    style={{
                      fontSize: "11px",
                      color: "var(--muted-foreground)",
                      textTransform: "uppercase",
                      fontWeight: 700,
                    }}
