                        {rolesList.map((role) => {
                          const cellState = permissions[mod.id][role.id];
                          return (
                            <td key={role.id} className="text-center">
                              <div
                                onClick={() => toggleCell(mod.id, role.id)}
                                className="inline-flex items-center justify-center rounded-lg cursor-pointer select-none transition-all"
                                style={{
                                  width: "80px",
                                  height: "32px",
                                  fontSize: "12px",
                                  fontWeight: 700,
                                  backgroundColor:
                                    cellState === "full"
                                      ? "rgba(0, 184, 124, 0.1)"
                                      : cellState === "view"
                                        ? "rgba(14, 165, 233, 0.1)"
                                        : "var(--muted)",
                                  color:
                                    cellState === "full"
                                      ? "#00B87C"
                                      : cellState === "view"
                                        ? "#0EA5E9"
                                        : "var(--muted-foreground)",
                                }}
                              >
                                {cellState === "full"
                                  ? "Full"
                                  : cellState === "view"
                                    ? "View"
                                    : "ΓÇö"}
                              </div>
                            </td>
                          );
                        })}
                      </tr>
                    ))}
                </React.Fragment>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
