        setIsSubmitting(false);
        closeModal();
      }, 1000);
    };

    const handleDeleteLeaveType = () => {
      setIsSubmitting(true);
      setTimeout(() => {
        setLeaveTypesList(
          leaveTypesList.filter((l) => l.code !== selectedLeaveType?.code),
