      setIsSubmitting(true);
      setTimeout(() => {
        setUsersList(
          usersList.map((u) =>
            u.email === selectedUser?.email
              ? {
                  ...u,
                  name: editForm.name,
                  email: editForm.email,
                  role: editForm.role,
                  dept: editForm.dept,
                  location: editForm.location,
                  status: editForm.status,
                }
              : u,
          ),
        );
        setIsSubmitting(false);
        showToast("User updated successfully", "success");
        closeModal();
      }, 1000);
