        setUsersList(
          usersList.map((u) =>
            u.email === selectedUser?.email ? { ...u, status: "Active" } : u,
          ),
        );
        setIsSubmitting(false);
        showToast("User reactivated successfully", "success");
        closeModal();
      }, 1000);
