      const isEdit = activeModal === "edit_leave_type";
      return (
        <div
          className="fixed inset-0 flex items-center justify-center p-4 z-[2000]"
          style={{ backgroundColor: "rgba(0,0,0,0.6)" }}
        >
          <div
