                    style={{
                      backgroundColor: "var(--input-background)",
                      borderColor: "var(--border)",
                      color: "var(--foreground)",
                    }}
                  />
                </div>
                <div>
                  <label
                    style={{
                      display: "block",
                      fontSize: "11px",
                      fontWeight: 700,
                      color: "var(--muted-foreground)",
                      textTransform: "uppercase",
                      marginBottom: "6px",
                    }}
                  >
                    Leave Code *
                  </label>
                  <input
                    type="text"
                    value={leaveTypeForm.code}
                    onChange={(e) =>
                      setLeaveTypeForm({
