                    className="w-full rounded-xl px-3 py-2.5 text-sm outline-none border transition-all"
                    style={{
                      backgroundColor: "var(--input-background)",
                      borderColor: "var(--border)",
                      color: "var(--foreground)",
                    }}
                  />
                </div>
