                      fontSize: "13px",
                      color: "var(--foreground)",
                      fontWeight: 500,
                    }}
                  >
                    Encashment Allowed
                  </label>
                </div>
                <div className="flex items-center gap-3">
                  <input
                    type="checkbox"
                    id="appReq"
                    checked={leaveTypeForm.approvalRequired}
                    onChange={(e) =>
                      setLeaveTypeForm({
                        ...leaveTypeForm,
                        approvalRequired: e.target.checked,
