          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label
                  style={{
                    display: "block",
                    fontSize: "11px",
                    fontWeight: 700,
                    color: "var(--muted-foreground)",
                    textTransform: "uppercase",
                    marginBottom: "6px",
                  }}
                >
                  Role Name <span className="text-red-500">*</span>
                </label>
                <input
                  type="text"
                  value={roleForm.name}
                  onChange={(e) =>
                    setRoleForm({ ...roleForm, name: e.target.value })
                  }
                  className="w-full rounded-xl px-3 py-2.5 text-sm outline-none border transition-all focus:border-[var(--primary)]"
                  style={{
                    backgroundColor: "var(--input-background)",
                    borderColor: "var(--border)",
                    color: "var(--foreground)",
                  }}
                  placeholder="e.g. HR Administrator"
                />
              </div>
              <div>
                <label
                  style={{
                    display: "block",
                    fontSize: "11px",
                    fontWeight: 700,
                    color: "var(--muted-foreground)",
                    textTransform: "uppercase",
                    marginBottom: "6px",
                  }}
                >
                  Status
                </label>
                <select
                  value={roleForm.status}
                  onChange={(e) =>
                    setRoleForm({ ...roleForm, status: e.target.value })
                  }
                  className="w-full rounded-xl px-3 py-2.5 text-sm outline-none border transition-all focus:border-[var(--primary)]"
                  style={{
                    backgroundColor: "var(--input-background)",
                    borderColor: "var(--border)",
                    color: "var(--foreground)",
                  }}
                >
                  <option value="Active">Active</option>
                  <option value="Inactive">Inactive</option>
                </select>
              </div>
            </div>

            <div>
              <label
                style={{
                  display: "block",
                  fontSize: "11px",
                  fontWeight: 700,
                  color: "var(--muted-foreground)",
                  textTransform: "uppercase",
                  marginBottom: "6px",
                }}
              >
                Description
              </label>
              <textarea
                value={roleForm.description}
                onChange={(e) =>
                  setRoleForm({ ...roleForm, description: e.target.value })
                }
                className="w-full rounded-xl px-3 py-2.5 text-sm outline-none border transition-all focus:border-[var(--primary)] resize-none"
                style={{
                  backgroundColor: "var(--input-background)",
                  borderColor: "var(--border)",
                  color: "var(--foreground)",
                  minHeight: "80px",
                }}
                placeholder="Describe the responsibilities of this role..."
              />
            </div>

            {activeModal === "edit_role" && selectedRoleForEdit && (
              <div
                className="flex items-center gap-2 px-3 py-2 rounded-lg"
                style={{ backgroundColor: "var(--muted)" }}
              >
                <Users size={14} style={{ color: "var(--muted-foreground)" }} />
                <span
                  style={{
                    fontSize: "12px",
                    color: "var(--muted-foreground)",
                    fontWeight: 500,
                  }}
                >
                  Assigned to{" "}
                  <strong style={{ color: "var(--foreground)" }}>
                    {selectedRoleForEdit.members}
                  </strong>{" "}
                  users
                </span>
              </div>
            )}

            <div>
              <div className="flex items-center justify-between mb-4">
                <label
                  style={{
                    display: "block",
                    fontSize: "13px",
                    fontWeight: 700,
                    color: "var(--foreground)",
                    textTransform: "none",
                  }}
                >
                  Module Permissions
                </label>
                <button
                  onClick={() => {
                    const newPerms = { ...roleForm.permissions };
                    Object.keys(newPerms).forEach((k) => (newPerms[k] = "no"));
                    setRoleForm({ ...roleForm, permissions: newPerms });
                  }}
                  className="text-[12px] font-semibold hover:underline transition-colors"
                  style={{
                    color: "var(--muted-foreground)",
                    background: "none",
                    border: "none",
                    cursor: "pointer",
                  }}
                >
                  Clear All
                </button>
              </div>

              <div
                className="border rounded-xl overflow-hidden"
                style={{
                  borderColor: "var(--border)",
                  maxHeight: "40vh",
                  overflowY: "auto",
