                  <thead
                    className="sticky top-0 z-10"
                    style={{ backgroundColor: "var(--muted)" }}
                  >
                    <tr>
                      <th
                        className="py-3 px-4 text-[11px] font-bold uppercase tracking-wider"
                        style={{ color: "var(--muted-foreground)" }}
                      >
