                fontWeight: 700,
                color: "var(--foreground)",
                margin: 0,
              }}
            >
              {title}
            </h3>
            <button
              onClick={closeModal}
              className="text-2xl hover:opacity-70 transition-all cursor-pointer"
              style={{
                color: "var(--muted-foreground)",
                background: "none",
                border: "none",
