        </div>
      </div>

      {/* MOBILE DRAWER TOGGLE */}
      <button
        onClick={() => setIsSidebarOpen(!isSidebarOpen)}
        className="md:hidden flex items-center gap-2 mb-4 px-4 py-2 rounded-xl cursor-pointer transition-all border select-none"
